custom_fields.hero:
[[[
function clean(value) {
  const text = value == null ? '' : String(value);
  return ['unknown', 'unavailable', 'none', ''].includes(text.toLowerCase()) ? '' : text;
}
function ageText(value) {
  const stamp = value ? new Date(value) : null;
  if (!stamp || Number.isNaN(stamp.getTime())) return '';
  const seconds = Math.max(0, Math.round((Date.now() - stamp.getTime()) / 1000));
  if (seconds < 90) return 'published just now';
  const minutes = Math.round(seconds / 60);
  if (minutes < 90) return 'published ' + minutes + 'm ago';
  const hours = Math.round(minutes / 60);
  return 'published ' + hours + 'h ago';
}
const roomObj = states['sensor.room_health_state'];
const mqttRoomObj = states['sensor.healthsave_room_health_state'];
let rawState = clean(roomObj && roomObj.state) || clean(mqttRoomObj && mqttRoomObj.state) || 'Balanced';
if (rawState.toLowerCase && rawState.toLowerCase() === 'normal') rawState = 'Balanced';
const state = rawState;
const reasonRaw = states['input_text.room_health_reason'] ? states['input_text.room_health_reason'].state : 'Watching the room and body state.';
const reason = reasonRaw.replace(/HealthTrack metrics/gi, 'Wearable metrics');
const hrvState = states['sensor.healthsave_hrv'] ? Number(states['sensor.healthsave_hrv'].state) : NaN;
const baseState = states['sensor.healthsave_hrv_7d_avg'] ? Number(states['sensor.healthsave_hrv_7d_avg'].state) : NaN;
const loadState = states['sensor.nervous_load'] ? Number(states['sensor.nervous_load'].state) : NaN;
const computedLoad = Number.isFinite(hrvState) && Number.isFinite(baseState) && baseState > 0
  ? Math.max(0, Math.round((100 * (baseState - hrvState)) / baseState))
  : NaN;
const loadNumber = Number.isFinite(loadState) ? Math.round(loadState) : computedLoad;
const load = Number.isFinite(loadNumber) ? loadNumber + '%' : '--';
const hrvText = Number.isFinite(hrvState) && Number.isFinite(baseState) && baseState > 0
  ? Math.round((hrvState / baseState) * 100) + '% of baseline'
  : 'baseline pending';
const hrRaw = clean(states['sensor.healthsave_heart_rate'] && states['sensor.healthsave_heart_rate'].state);
const hrPill = hrRaw
  ? '<span><b>' + hrRaw + '</b> bpm recent HR</span>'
  : '<span><b>pending</b> HR sample</span>';
const mode = states['input_select.lighting_mode'] ? states['input_select.lighting_mode'].state : 'Adaptive';
const sourceObj = states['sensor.healthsave_source_model'];
const source = clean(sourceObj && sourceObj.state) || 'source pending';
const observedObj = states['sensor.healthsave_snapshot_observed_at'] || states['sensor.healthsave_observed_at'];
const sync = ageText(clean(observedObj && observedObj.state)) || ageText(states['sensor.healthsave_heart_rate'] && states['sensor.healthsave_heart_rate'].last_updated) || 'publish pending';
const today = new Intl.DateTimeFormat('en-US', { weekday: 'short', month: 'short', day: 'numeric' }).format(new Date());
return '<div class="hero">' +
  '<div class="topline"><span class="sun-dot">+</span><span>' + today + '</span><span>' + sync + '</span><span>' + source + '</span></div>' +
  '<div class="title">Good night, body.</div>' +
  '<div class="subtitle">' + state + ' room state</div>' +
  '<div class="reason">' + reason + '</div>' +
  '<div class="pills">' +
    '<span><b>' + load + '</b> nervous load</span>' +
    '<span><b>' + hrvText + '</b></span>' +
    hrPill +
    '<span><b>' + mode + '</b> room mode</span>' +
    '<span class="manual">manual wins</span>' +
  '</div>' +
'</div>';
]]]

