custom_fields.signal:
[[[
function clean(value) {
  const text = value == null ? '' : String(value);
  return ['unknown', 'unavailable', 'none', ''].includes(text.toLowerCase()) ? '' : text;
}
const hrv = states['sensor.healthsave_hrv'] ? Number(states['sensor.healthsave_hrv'].state) : NaN;
const base = states['sensor.healthsave_hrv_7d_avg'] ? Number(states['sensor.healthsave_hrv_7d_avg'].state) : NaN;
const loadObj = states['sensor.nervous_load'];
const loadState = loadObj ? Number(loadObj.state) : NaN;
const loadCalc = Number.isFinite(hrv) && Number.isFinite(base) && base > 0 ? Math.max(0, Math.round((100 * (base - hrv)) / base)) : NaN;
const load = Number.isFinite(loadState) ? Math.round(loadState) : loadCalc;
const hr = clean(states['sensor.healthsave_heart_rate'] && states['sensor.healthsave_heart_rate'].state) || 'pending';
const rhr = states['sensor.healthsave_resting_heart_rate'] ? states['sensor.healthsave_resting_heart_rate'].state : '--';
const sleep = states['sensor.healthsave_last_sleep_hours'] ? states['sensor.healthsave_last_sleep_hours'].state : '--';
const reasonRaw = states['input_text.room_health_reason'] ? states['input_text.room_health_reason'].state : 'Waiting for automation reason.';
const reason = reasonRaw.replace(/HealthTrack metrics/gi, 'Wearable metrics');
const formula = Number.isFinite(hrv) && Number.isFinite(base) && Number.isFinite(load)
  ? '(' + base.toFixed(1) + ' - ' + hrv.toFixed(1) + ') / ' + base.toFixed(1) + ' = ' + load + '%'
  : 'waiting for HRV + baseline';
return '<div class="signal-card">' +
  '<div class="kicker">signal math</div>' +
  '<div class="big">' + (Number.isFinite(load) ? load + '%' : '--') + '</div>' +
  '<div class="caption">nervous load = HRV below personal 7-day baseline</div>' +
  '<div class="formula">' + formula + '</div>' +
  '<div class="signal-grid">' +
    '<span><b>' + hr + '</b><small>recent HR</small></span>' +
    '<span><b>' + rhr + '</b><small>resting HR</small></span>' +
    '<span><b>' + sleep + 'h</b><small>sleep</small></span>' +
  '</div>' +
  '<div class="reason-line">' + reason + '</div>' +
  '<div class="note">Derived HA signal, not a medical score.</div>' +
'</div>';
]]]
